'use server';

import { db } from '@/db';
import { products, frameReservations } from '@/db/schema';
import { eq, sql } from 'drizzle-orm';
import type { CancelFrameReservationInput, FrameReservation } from '../types/reservation.types';

/**
 * Annule ou marque comme expirée une réservation
 * Libère la quantité réservée sans toucher au stock réel
 */
export async function cancelFrameReservation(
  input: CancelFrameReservationInput
): Promise<FrameReservation> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return await db.transaction(async (tx: any) => {

    // 1) جلب الحجز
    const reservation = await tx.query.frameReservations.findFirst({
      where: eq(frameReservations.id, input.reservationId),
    });

    if (!reservation) {
      throw new Error('Réservation introuvable');
    }

    // لا يمكن إلغاء حجز مكتمل
    if (reservation.status === 'COMPLETED') {
      throw new Error('Impossible d\'annuler une réservation complétée');
    }

    // إذا كان بالفعل ملغى أو منتهي، رجّعه كما هو
    if (reservation.status === 'CANCELLED' || reservation.status === 'EXPIRED') {
      return reservation as FrameReservation;
    }

    // 2) إرجاع الكمية المحجوزة للستوك
    for (const item of reservation.items as any[]) {
      await tx
        .update(products)
        .set({
          reservedQuantity: sql`${products.reservedQuantity} - ${item.quantity}`,
        })
        .where(eq(products.id, item.productId));
    }

    // 3) تحديد الحالة الجديدة
    const newStatus = input.setExpired ? 'EXPIRED' : 'CANCELLED';
    const cancelMessage = input.setExpired
      ? '[Expiration automatique]'
      : `[Annulation]${input.reason ? ' ' + input.reason : ''}`;

    // 4) تحديث الحجز
    const [updated] = await tx
      .update(frameReservations)
      .set({
        status: newStatus,
        notes: reservation.notes
          ? `${reservation.notes}\n${cancelMessage}`
          : cancelMessage,
      })
      .where(eq(frameReservations.id, input.reservationId))
      .returning();

    return updated as FrameReservation;
  });
}

'use server';

import { db } from '@/db';
import { products, frameReservations } from '@/db/schema';
import { eq, sql } from 'drizzle-orm';
import type { CompleteFrameReservationInput, FrameReservation } from '../types/reservation.types';

/**
 * Termine une réservation en la convertissant en vente
 * Le stock est déduit et la quantité réservée est libérée
 */
export async function completeFrameReservation(
  input: CompleteFrameReservationInput
): Promise<FrameReservation> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return await db.transaction(async (tx: any) => {

    // 1) جلب الحجز
    const reservation = await tx.query.frameReservations.findFirst({
      where: eq(frameReservations.id, input.reservationId),
    });

    if (!reservation) {
      throw new Error('Réservation introuvable');
    }

    if (reservation.status !== 'PENDING') {
      throw new Error(`Cette réservation a déjà été traitée (statut: ${reservation.status})`);
    }

    // 2) تحديث stock لكل منتج
    for (const item of reservation.items as any[]) {
      await tx
        .update(products)
        .set({
          quantiteStock: sql`${products.quantiteStock} - ${item.quantity}`,
          reservedQuantity: sql`${products.reservedQuantity} - ${item.quantity}`,
        })
        .where(eq(products.id, item.productId));
    }

    // 3) تحديث الحجز
    const [updated] = await tx
      .update(frameReservations)
      .set({
        status: 'COMPLETED',
        completedAt: new Date(),
        saleId: input.saleId,
        notes: reservation.notes
          ? `${reservation.notes}\n[Converti en vente #${input.saleId}]`
          : `Converti en vente #${input.saleId}`,
      })
      .where(eq(frameReservations.id, input.reservationId))
      .returning();

    return updated as FrameReservation;
  });
}

'use server';

import { db } from '@/db';
import { products, frameReservations } from '@/db/schema';
import { eq, inArray, sql } from 'drizzle-orm';
import { addDays } from 'date-fns';
import type { CreateFrameReservationInput, FrameReservation } from '../types/reservation.types';

/**
 * Crée une nouvelle réservation de monture
 * Adapte les noms de champs du schema (nom instead of name, quantiteStock instead of stockQuantity)
 */
export async function createFrameReservation(
  input: CreateFrameReservationInput
): Promise<FrameReservation> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return await db.transaction(async (tx: any) => {

    // 1) جلب المنتجات
    const productIds = input.items.map(i => i.productId);
    const fetchedProducts = await tx.query.products.findMany({
      where: inArray(products.id, productIds),
    });

    if (fetchedProducts.length !== productIds.length) {
      throw new Error('Un ou plusieurs produits introuvables');
    }

    // 2) التحقق من النوع والكمية المتاحة
    const reservationItems = [];

    for (const item of input.items) {
      const product = fetchedProducts.find((p: { id: number }) => p.id === item.productId);
      if (!product) continue;

      /*
      // تحقق أن المنتج من نوع MONTURE (Removed per request to allow reservation of any product)
      if (product.type !== 'MONTURE') {
        throw new Error(
          `Le produit "${product.nom}" n'est pas une monture. Seules les montures peuvent être réservées.`
        );
      }
      */

      // حساب المتاح
      const available = product.quantiteStock - product.reservedQuantity;

      /*
      if (available < item.quantity) {
        // Allow backorder for reservations
        // throw new Error(
        //   `Stock insuffisant pour "${product.nom}". Disponible: ${available}, demandé: ${item.quantity}`
        // );
      }
      */

      reservationItems.push({
        productId: product.id,
        productName: product.nom,
        reference: product.reference,
        quantity: item.quantity,
        unitPrice: parseFloat(product.prixVente.toString()),
      });
    }

    const totalAmount = reservationItems.reduce((sum, item) => sum + (item.unitPrice * item.quantity), 0);

    // 3) حساب التواريخ
    const reservationDate = new Date();
    const expiryDate = addDays(reservationDate, input.expiryDays ?? 7);

    // 4) إدخال الحجز
    const [reservation] = await tx
      .insert(frameReservations)
      .values({
        storeId: input.storeId,
        clientId: input.clientId,
        clientName: input.clientName,
        status: 'PENDING',
        items: reservationItems,
        reservationDate,
        expiryDate,
        totalAmount: totalAmount.toString(),
        depositAmount: '0',
        remainingAmount: totalAmount.toString(),
        notes: input.notes,
      })
      .returning();


    // 5) تحديث reservedQuantity لكل منتج
    for (const item of input.items) {
      await tx
        .update(products)
        .set({
          reservedQuantity: sql`${products.reservedQuantity} + ${item.quantity}`,
        })
        .where(eq(products.id, item.productId));
    }

    return reservation as FrameReservation;
  });
}

import { db } from '@/db';
import { devis, sales, shopProfiles } from '@/db/schema';
import { and, eq } from 'drizzle-orm';
import {
  DEFAULT_DOCUMENT_SETTINGS,
  CURRENT_DOC_VERSION,
  type DocumentSettings,
  type DocType,
  type DocumentSettingsBase,
} from '@/types/document-settings-types';

export type DocumentSettingsUpdate = {
  default?: Partial<DocumentSettingsBase>;
  overrides?: Partial<Record<DocType, Partial<DocumentSettingsBase>>>;
};

function deepMerge<T>(target: T, source: Partial<T>): T {
  const result: any = { ...(target as any) };
  for (const key in source) {
    const value = (source as any)[key];
    if (value !== undefined) {
      if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
        result[key] = deepMerge((target as any)[key], value);
      } else {
        result[key] = value;
      }
    }
  }
  return result as T;
}

function migrateSettings(settings: any): DocumentSettings {
  let s: any = { ...(settings || {}) };

  if (!s.version) s.version = 1;

  if (s.version < 2) {
    s.default = { ...(s.default || {}), theme: 'default', language: 'fr' };
    s.version = 2;
  }

  if (s.version < 3) {
    s.default = {
      ...(s.default || {}),
      showWatermark: false,
      showPageNumber: true,
      showSignature: false,
      watermarkText: 'CONFIDENTIEL',
      fontSize: 'medium',
    };
    s.version = 3;
  }

  if (s.version > CURRENT_DOC_VERSION) {
    s.version = CURRENT_DOC_VERSION;
  }

  return s as DocumentSettings;
}

export function mergeWithDefaults(
  settings: Partial<DocumentSettings> | null | undefined
): DocumentSettings {
  if (!settings) return DEFAULT_DOCUMENT_SETTINGS;
  const migrated = migrateSettings(settings);
  return deepMerge(DEFAULT_DOCUMENT_SETTINGS, migrated);
}

export function resolveSettingsForDocType(
  settings: DocumentSettings,
  docType: DocType
): DocumentSettingsBase {
  const base = settings.default;
  const override = settings.overrides?.[docType] ?? {};
  return { ...base, ...override };
}

export async function resolveDocumentSettings(
  shopId: number,
  snapshot?: any | null
): Promise<DocumentSettings> {
  // ✅ UPDATED
  // If snapshot is null/undefined -> always load latest from DB
  if (snapshot === null || snapshot === undefined) {
    return getDocumentSettings(shopId);
  }

  // Snapshot exists -> use it, but be robust against corrupted shapes
  try {
    return mergeWithDefaults(snapshot);
  } catch {
    console.warn('[resolveDocumentSettings] Snapshot invalide, fallback vers DB');
    return getDocumentSettings(shopId);
  }
}

export async function getDocumentSettings(shopId: number): Promise<DocumentSettings> {
  const shop = await db.query.shopProfiles.findFirst({
    where: eq(shopProfiles.id, shopId),
    columns: { documentSettings: true },
  });

  return mergeWithDefaults(shop?.documentSettings as any);
}

export async function updateDocumentSettings(
  shopId: number,
  updates: DocumentSettingsUpdate
): Promise<DocumentSettings> {
  const current = await getDocumentSettings(shopId);

  const profile = await db.query.shopProfiles.findFirst({
    where: eq(shopProfiles.id, shopId),
    columns: { userId: true },
  });

  if (!profile) {
    throw new Error('Shop not found');
  }

  const updated: DocumentSettings = {
    ...current,
    version: (current.version || 0) + 1,
    default: deepMerge(current.default, updates.default || {}),
    overrides: deepMerge(current.overrides || {}, updates.overrides || {}),
  };

  // ✅ UPDATED
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  await db.transaction(async (tx: any) => {
    // 1) Update shop profile settings
    await tx
      .update(shopProfiles)
      .set({
        documentSettings: updated as any,
        documentSettingsVersion: updated.version,
        documentSettingsUpdatedAt: new Date(),
      })
      .where(eq(shopProfiles.id, shopId));

    // 2) Propagate snapshot only for non-final documents
    //    - Sales: status='brouillon'
    //    - Devis: status='EN_ATTENTE'
    await tx
      .update(sales)
      .set({ documentSettingsSnapshot: updated as any })
      .where(and(eq(sales.userId, profile.userId), eq(sales.status, 'brouillon')));

    await tx
      .update(devis)
      .set({ documentSettingsSnapshot: updated as any })
      .where(and(eq(devis.userId, profile.userId), eq(devis.status, 'EN_ATTENTE')));
  });

  return updated;
}
